#include<iostream>#include<vector>#include<cmath>#include<algorithm>#define ll long longusing namespace std;ll lcm(ll a,ll b){    return (a / __gcd(a,b))*b;}int main(){    ios_base::sync_with_stdio(false);    cin.tie(NULL);    int t;    cin>>t;    while(t--){        ll n,x,y;        cin>>n>>x>>y;        ll common= n/lcm(x,y);        ll pos_x= (n/x) - common;        ll pos_y= (n/y) - common;        ll sum_x=( pos_x * (n + (n - pos_x + 1)))/2;        ll sum_y= (pos_y * (1 + pos_y))/2;        cout<<sum_x - sum_y<<"\n";    }        }